@Component({
  selector: 'app-login',
  imports: [NavBar, MatIcon, Bouton, MatFormField, MatLabel, MatInput, MatDivider, RouterLink, ReactiveFormsModule],
  templateUrl: './login.html',
  styleUrl: './login.scss',
})
export class Login {
  private authService = inject(AuthService);
  private fb = inject(FormBuilder);
  private router = inject(Router);
  private sessionService = inject(SessionService);

  public errorMessage: string | null = null;

  private destroyRef = inject(DestroyRef);

  public form = this.fb.group({
    identifiant: [
      '',
      [
        Validators.required
      ]
    ],
    password: [
      '',
      [
        Validators.required,
        Validators.minLength(8),
        passwordValidator
      ]
    ]
  });

  public submit(): void {
    const loginRequest = this.form.value as LoginRequest;
    this.errorMessage = null
    this.authService.login(loginRequest)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response: SessionInformations) => {
          this.sessionService.logIn(response);
          this.router.navigate(['/articles']);
        },
        error: (err: HttpErrorResponse) => {
          this.errorMessage = err.error?.message || err.error || "Une erreur est survenue";
        },
      });
  }
}

