    tap(user => {
      this.form.patchValue({
        username: user.username,
        email: user.email
      });
    })
  );

  public desabonnement(id: number): void {
    this.themeService.desabonnement(id)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: () => this.user$ = this.userService.user()
      });
  }

