export const environment = {
    baseUrl: 'http://localhost:9000/api',
    production: false
};

import { HttpInterceptorFn } from "@angular/common/http";
import { environment } from "../../../environments/environment";

export const baseUrlInterceptor: HttpInterceptorFn = (req, next) => {
    const apiReq = req.clone({
        url: `${environment.baseUrl}/${req.url}`
    });

    return next(apiReq);
}

import { HttpEvent, HttpHandlerFn, HttpRequest } from "@angular/common/http";
import { SessionService } from "../services/session";
import { inject } from "@angular/core";
import { Observable } from "rxjs";

export function customJwtInterceptorFn(request: HttpRequest<unknown>, next: HttpHandlerFn): Observable<HttpEvent<unknown>> {
  const sessionService = inject(SessionService);
  if (sessionService.isLogged) {
    request = request.clone({
      setHeaders: {
        Authorization: `Bearer ${sessionService.sessionInformations!.token}`,
      },
    });
  }
  return next(request);
}

import { ApplicationConfig, provideBrowserGlobalErrorListeners, provideZoneChangeDetection } from '@angular/core';
import { provideRouter } from '@angular/router';

import { routes } from './app.routes';
import { provideHttpClient, withInterceptors } from '@angular/common/http';
import { baseUrlInterceptor } from './core/interceptors/baseUrlInterceptor';
import { customJwtInterceptorFn } from './core/interceptors/jwtInterceptor';

export const appConfig: ApplicationConfig = {
  providers: [
    provideHttpClient(withInterceptors([baseUrlInterceptor, customJwtInterceptorFn])),
    provideBrowserGlobalErrorListeners(),
    provideRouter(routes),
    provideZoneChangeDetection({ eventCoalescing: true })
  ]
};

